pred GeneratedPlan {

    // Patient is currently in the water
    P.location = InWater

    // Nothing has been done yet — we are determining the safe action plan from scratch
    no P.done

    // Define the full dependency chain for a water rescue protocol
    // Every action's prerequisites are explicitly captured

    // AssessSceneSafety is always first — no prerequisites
    some d1: Dependency | d1.step = AssessSceneSafety and no d1.requires

    // Call911 requires scene safety assessed first
    some d2: Dependency | d2.step = Call911 and d2.requires = AssessSceneSafety

    // RemoveFromWater requires scene is safe and 911 called
    some d3: Dependency | d3.step = RemoveFromWater and 
        d3.requires = AssessSceneSafety + Call911

    // CheckResponse requires patient is out of water
    some d4: Dependency | d4.step = CheckResponse and 
        d4.requires = AssessSceneSafety + Call911 + RemoveFromWater

    // GiveRescueBreaths requires response has been checked
    some d5: Dependency | d5.step = GiveRescueBreaths and 
        d5.requires = AssessSceneSafety + Call911 + RemoveFromWater + CheckResponse

    // StartCompressions requires rescue breaths given (drowning protocol: breaths first)
    some d6: Dependency | d6.step = StartCompressions and 
        d6.requires = AssessSceneSafety + Call911 + RemoveFromWater + CheckResponse + GiveRescueBreaths

    // UseAED requires compressions started
    some d7: Dependency | d7.step = UseAED and 
        d7.requires = AssessSceneSafety + Call911 + RemoveFromWater + CheckResponse + GiveRescueBreaths + StartCompressions

    // Exactly 7 dependencies — one per action
    #Dependency = 7

    // The exact next safe action is the one whose all prerequisites are satisfied
    // Since nothing is done (no P.done), only actions with NO prerequisites are safe
    // That means the next action is AssessSceneSafety
    // We enforce: the only action whose requires are all in P.done is AssessSceneSafety
    all d: Dependency | (d.requires in P.done) implies d.step = AssessSceneSafety
}

pred GeneratedPlan {

    // Patient is on land, having been removed from water
    P.location = OnLand

    // Actions already completed: scene was assessed safe, 911 was called, patient was removed from water
    P.done = AssessSceneSafety + Call911 + RemoveFromWater

    // CheckResponse has NOT yet been done (it is the next action)
    CheckResponse not in P.done

    // Dependency: RemoveFromWater requires AssessSceneSafety
    some d1: Dependency |
        d1.step = RemoveFromWater and
        d1.requires = AssessSceneSafety

    // Dependency: Call911 requires AssessSceneSafety
    some d2: Dependency |
        d2.step = Call911 and
        d2.requires = AssessSceneSafety

    // Dependency: CheckResponse requires RemoveFromWater (patient must be on land first)
    some d3: Dependency |
        d3.step = CheckResponse and
        d3.requires = RemoveFromWater

    // Dependency: GiveRescueBreaths requires CheckResponse
    some d4: Dependency |
        d4.step = GiveRescueBreaths and
        d4.requires = CheckResponse

    // Dependency: StartCompressions requires CheckResponse
    some d5: Dependency |
        d5.step = StartCompressions and
        d5.requires = CheckResponse

    // Dependency: UseAED requires CheckResponse
    some d6: Dependency |
        d6.step = UseAED and
        d6.requires = CheckResponse

    // The immediate next action is CheckResponse:
    // It is the action whose all prerequisites are satisfied (in done) 
    // but which itself has not been performed yet
    all dep: Dependency |
        (dep.requires in P.done and dep.step not in P.done)
        implies dep.step = CheckResponse

    // All dependencies are distinct (one per step defined above)
    #Dependency = 6
}

